import numpy as np
import pandas as pd

def compute_log_returns(price_series):
  """
  Computes log returns from a price series.

  Args:
    price_series: A Pandas Series or NumPy array representing the price series.

  Returns:
    A Pandas Series with the log returns.  Returns an empty series if the input is empty or has fewer than 2 elements.
  """

  if isinstance(price_series, pd.Series):
    if price_series.empty or len(price_series) < 2:
        return pd.Series()
    price_series = price_series.astype(float)  # Ensure numeric type
    log_returns = np.log(price_series / price_series.shift(1))
    return log_returns.iloc[1:]  # Remove the first NaN value
  elif isinstance(price_series, np.ndarray):
    if price_series.size == 0 or price_series.size < 2:
        return pd.Series()
    price_series = price_series.astype(float) # Ensure numeric type
    log_returns = np.log(price_series[1:] / price_series[:-1])
    return pd.Series(log_returns)
  else:
      try:
          price_series = pd.Series(price_series)
          if price_series.empty or len(price_series) < 2:
              return pd.Series()
          price_series = price_series.astype(float)  # Ensure numeric type
          log_returns = np.log(price_series / price_series.shift(1))
          return log_returns.iloc[1:]  # Remove the first NaN value
      except:
          return pd.Series()
